public interface IFrameReceiver
{
/// <summary>
/// A callback method that is called by a native library every time a new frame is available from an image capture device.
/// </summary>
/// <param name="frame">A pointer to the raw bytes of the frame.</param>
/// <param name="width">The width of the frame in pixels.</param>
/// <param name="height">The height of the frame in pixels.</param>
void ReceiveFrame(IntPtr frame, int width, int height);
}

/// <summary>
/// An interface that defines a callback method for reporting values to an external library.
/// </summary>
public interface IValueReporter
{
/// <summary>
/// A callback method that is implemented by an external library that will plot the given value in a real-time chart.
/// </summary>
/// <param name="value">The value to be reported.</param>
void Report(double value);
}

/// <summary>
/// A class that implements the IFrameReceiver interface and calculates the average pixel value of each frame.
/// </summary>
public class FrameCalculator : IFrameReceiver, IDisposable
{
private readonly IValueReporter _reporter;
private readonly ConcurrentQueue<byte[]> _frames;
private bool _disposed;

/// <summary>
/// Initializes a new instance of the FrameCalculator class with a given value reporter.
/// </summary>
/// <param name="reporter">The value reporter to be used.</param>
public FrameCalculator(IValueReporter reporter)
{
_reporter = reporter ?? throw new ArgumentNullException(nameof(reporter));
_frames = new ConcurrentQueue<byte[]>();
}

/// <summary>
/// Receives a frame from the native library and enqueues it for calculation.
/// </summary>
/// <param name="frame">A pointer to the raw bytes of the frame.</param>
/// <param name="width">The width of the frame in pixels.</param>
/// <param name="height">The height of the frame in pixels.</param>
public void ReceiveFrame(IntPtr frame, int width, int height)
{
if (_disposed)
throw new ObjectDisposedException(nameof(FrameCalculator));

if (frame == IntPtr.Zero)
throw new ArgumentException("Invalid frame pointer.", nameof(frame));

if (width <= 0 || height <= 0)
throw new ArgumentOutOfRangeException("Invalid frame size.", nameof(width) + " or " + nameof(height));

// Copy the frame data to a managed array
int size = width * height;
byte[] buffer = new byte[size];
Marshal.Copy(frame, buffer, 0, size);

// Enqueue the frame for calculation
_frames.Enqueue(buffer);

// Create a list of tasks that will run the calculation method for each frame
List<Task<double>> tasks = new List<Task<double>>();
foreach (var f in _frames)
{
// Start a new task with a lambda expression that calls the CalculateAverage method with the frame as a parameter
tasks.Add(Task.Run(() => CalculateAverage(f)));
}

// Wait for all the tasks to complete and get the result as an array of doubles
double[] results = await Task.WhenAll(tasks);

// Calculate the average value of all the frames and report it
double average = results.Average();
_reporter.Report(average);
}

/// <summary>
/// Calculates the average pixel value of a single frame.
/// </summary>
/// <param name="frame">The frame to be calculated.</param>
/// <returns>The average pixel value of the frame.</returns>
