{
// Calculate the average pixel value using LINQ
double average = frame.Average(b => b);
return average;
}

/// <summary>
/// Disposes of the resources used by the FrameCalculator instance.
/// </summary>
public void Dispose()
{
if (!_disposed)
{
// Set the disposed flag to true
_disposed = true;

// Clear the frames queue
_frames.Clear();
}
}
}
