```csharp
using Newtonsoft.Json;
using Newtonsoft.Json.Linq;

public class JsonPathExample
{
    public static void Main()
    {
        // Your JSON data as a string
        string jsonData = @"{
            'name': 'John',
            'age': 30,
            'address': {
                'street': '123 Main St',
                'city': 'New York'
            },
            'friends': [
                { 'name': 'Alice' },
                { 'name': 'Bob' },
                { 'name': 'Charlie' }
            ]
        }";

        // Parse the JSON string
        JObject jsonObject = JObject.Parse(jsonData);

        // Using JSON Path to access data
        string name = (string)jsonObject.SelectToken("name");
        int age = (int)jsonObject.SelectToken("age");
        string city = (string)jsonObject.SelectToken("address.city");
        string secondFriend = (string)jsonObject.SelectToken("friends[1].name");

        // Displaying the results
        Console.WriteLine("Name: " + name);
        Console.WriteLine("Age: " + age);
        Console.WriteLine("City: " + city);
        Console.WriteLine("Second Friend: " + secondFriend);
    }
}
```

In this example, we're using `SelectToken` to retrieve specific values from the JSON data using JSON Path expressions. The expressions can navigate through objects, arrays, and properties in the JSON structure.

